1	import { HydrateClient } from "@repo/app-trpc/server";
2	import {
3	  SidebarInset,
4	  SidebarProvider,
5	  SidebarTrigger,
6	} from "@repo/ui/components/ui/sidebar";
7	import { parseError } from "@vendor/observability/error/next";
8	import { log } from "@vendor/observability/log/next";
9	import { Loader2 } from "lucide-react";
10	import type { Route } from "next";
11	import { notFound, redirect } from "next/navigation";
12	import { Suspense } from "react";
13	import { AppHeader } from "~/components/app-header";
14	import { AppSidebar } from "~/components/app-sidebar";
15	import { CommandPalette } from "~/components/command-palette";
16	import { OrgPageErrorBoundary } from "~/components/errors/org-page-error-boundary";
17	import { getGitHubBinding } from "~/lib/github-binding";
18	import { requireOrgAccess } from "~/lib/org-access-clerk";
19	
20	interface OrgLayoutProps {
21	  children: React.ReactNode;
22	  params: Promise<{ slug: string }>;
23	}
24	
25	/**
26	 * Organization layout - prefetches org data using user-scoped endpoint
27	 *
28	 * Flow:
29	 * 1. Layout verifies org access via requireOrgAccess (fetches org directly from Clerk by slug)
30	 * 2. Validates org access and sets up org context
31	 * 3. Procedure manually verifies user has access to the org
32	 * 4. Middleware's organizationSyncOptions syncs org from URL (happens in parallel)
33	 * 5. Data is hydrated to client → fast render
34	 * 6. Failure → error boundary catches → proper error UI
35	 *
36	 * Why we use requireOrgAccess instead of auth().orgSlug:
37	 * - After org name changes, setActive() updates cookies but there's propagation delay
38	 * - auth().orgSlug might return old slug or null during RSC request
39	 * - requireOrgAccess fetches org directly from Clerk by slug and verifies membership
40	 * - This avoids race conditions with Clerk cookie propagation
41	 */
42	export default async function OrgLayout({ children, params }: OrgLayoutProps) {
43	  const { slug } = await params;
44	
45	  let org: { id: string } | null = null;
46	  try {
47	    const access = await requireOrgAccess(slug);
48	    org = { id: access.org.id };
49	  } catch (error) {
50	    log.debug("[org-layout] access denied", { slug, error: parseError(error) });
51	    notFound();
52	  }
53	
54	  // Check GitHub binding — redirect to bind page if missing
55	  const binding = await getGitHubBinding(org.id);
56	  if (!binding || binding.status !== "active") {
57	    redirect(`/account/teams/new/bind?slug=${slug}` as Route);
58	  }
59	
60	  return (
61	    <HydrateClient>
62	      <OrgPageErrorBoundary orgSlug={slug}>
63	        <SidebarProvider className="!h-full !min-h-0 overflow-hidden bg-sidebar">
64	          <AppSidebar />
65	          <CommandPalette />
66	          {/* Right column: header (outside inset) + inset content below */}
67	          {/* pr-2 pb-2 creates the gap for the inset card — margin on SidebarInset doesn't work because w-full overflows */}
68	          <div className="flex min-h-0 flex-1 flex-col overflow-hidden lg:pr-2 lg:pb-2">
69	            {/* h-14 header — same visual level as sidebar's team-switcher row */}
70	            <div className="flex h-14 shrink-0 items-center px-4">
71	              <SidebarTrigger className="lg:hidden" />
72	              <Suspense fallback={<div className="h-8 w-8" />}>
73	                <AppHeader />
74	              </Suspense>
75	            </div>
76	            {/* Inset panel: 100% - h-14, rounded card floating in bg-sidebar */}
77	            <SidebarInset className="overflow-hidden lg:rounded-xl lg:shadow-sm">
78	              <Suspense fallback={<PageLoadingSkeleton />}>{children}</Suspense>
79	            </SidebarInset>
80	          </div>
81	        </SidebarProvider>
82	      </OrgPageErrorBoundary>
83	    </HydrateClient>
84	  );
85	}
86	
87	function PageLoadingSkeleton() {
88	  return (
89	    <div className="flex h-full min-h-0 w-full items-center justify-center">
90	      <Loader2 className="h-8 w-8 animate-spin text-muted-foreground" />
91	    </div>
92	  );
93	}
