import { db, githubOrgBindings } from "@db/app";
import { eq } from "drizzle-orm";
import { cache } from "react";

export const getGitHubBinding = cache(async (clerkOrgId: string) => {
  const rows = await db
    .select({
      id: githubOrgBindings.id,
      status: githubOrgBindings.status,
      githubOrgLogin: githubOrgBindings.githubOrgLogin,
      githubOrgAvatarUrl: githubOrgBindings.githubOrgAvatarUrl,
    })
    .from(githubOrgBindings)
    .where(eq(githubOrgBindings.clerkOrgId, clerkOrgId))
    .limit(1);
  return rows[0] ?? null;
});

