import type { TRPCRouterRecord } from "@trpc/server";
import { githubOrgBindings } from "@db/app/schema";
import { eq } from "drizzle-orm";
import { orgScopedProcedure } from "../../trpc";

export const githubBindingRouter = {
  get: orgScopedProcedure.query(async ({ ctx }) => {
    const rows = await ctx.db
      .select()
      .from(githubOrgBindings)
      .where(eq(githubOrgBindings.clerkOrgId, ctx.auth.orgId))
      .limit(1);
    return rows[0] ?? null;
  }),
} satisfies TRPCRouterRecord;

